/* Embedded meshopt_decoder (EXT_meshopt_compression) — single script load, avoids 404/HTML as .js */
// This file is part of meshoptimizer library and is distributed under the terms of MIT License.
// Copyright (C) 2016-2020, by Arseny Kapoulkine (arseny.kapoulkine@gmail.com)
var MeshoptDecoder = (function() {
	"use strict";

	// Built with clang version 11.0.0 (https://github.com/llvm/llvm-project.git 0160ad802e899c2922bc9b29564080c22eb0908c)
	// Built from meshoptimizer 0.14
	var wasm_base = "";
	var wasm_simd = "";

	// Uses bulk-memory and simd extensions
	var detector = new Uint8Array([0,97,115,109,1,0,0,0,1,4,1,96,0,0,3,3,2,0,0,5,3,1,0,1,12,1,0,10,22,2,12,0,65,0,65,0,65,0,252,10,0,0,11,7,0,65,0,253,15,26,11]);

	// Used to unpack wasm
	var wasmpack = new Uint8Array([32,0,65,253,3,1,2,34,4,106,6,5,11,8,7,20,13,33,12,16,128,9,116,64,19,113,127,15,10,21,22,14,255,66,24,54,136,107,18,23,192,26,114,118,132,17,77,101,130,144,27,87,131,44,45,74,156,154,70,167]);

	if (typeof WebAssembly !== 'object') {
		// This module requires WebAssembly to function
		return {
			supported: false,
		};
	}

	var wasm = wasm_base;

	if (WebAssembly.validate(detector)) {
		wasm = wasm_simd;
		console.log("Warning: meshopt_decoder is using experimental SIMD support");
	}

	var instance;

	var promise =
		WebAssembly.instantiate(unpack(wasm), {})
		.then(function(result) {
			instance = result.instance;
			instance.exports.__wasm_call_ctors();
		});

	function unpack(data) {
		var result = new Uint8Array(data.length);
		for (var i = 0; i < data.length; ++i) {
			var ch = data.charCodeAt(i);
			result[i] = ch > 96 ? ch - 71 : ch > 64 ? ch - 65 : ch > 47 ? ch + 4 : ch > 46 ? 63 : 62;
		}
		var write = 0;
		for (var i = 0; i < data.length; ++i) {
			result[write++] = (result[i] < 60) ? wasmpack[result[i]] : (result[i] - 60) * 64 + result[++i];
		}
		return result.buffer.slice(0, write);
	}

	function decode(fun, target, count, size, source, filter) {
		var sbrk = instance.exports.sbrk;
		var count4 = (count + 3) & ~3; // pad for SIMD filter
		var tp = sbrk(count4 * size);
		var sp = sbrk(source.length);
		var heap = new Uint8Array(instance.exports.memory.buffer);
		heap.set(source, sp);
		var res = fun(tp, count, size, sp, source.length);
		if (res == 0 && filter) {
			filter(tp, count4, size);
		}
		target.set(heap.subarray(tp, tp + count * size));
		sbrk(tp - sbrk(0));
		if (res != 0) {
			throw new Error("Malformed buffer data: " + res);
		}
	};

	var filters = {
		// legacy index-based enums for glTF
		0: "",
		1: "meshopt_decodeFilterOct",
		2: "meshopt_decodeFilterQuat",
		3: "meshopt_decodeFilterExp",
		// string-based enums for glTF
		NONE: "",
		OCTAHEDRAL: "meshopt_decodeFilterOct",
		QUATERNION: "meshopt_decodeFilterQuat",
		EXPONENTIAL: "meshopt_decodeFilterExp",
	};

	var decoders = {
		// legacy index-based enums for glTF
		0: "meshopt_decodeVertexBuffer",
		1: "meshopt_decodeIndexBuffer",
		2: "meshopt_decodeIndexSequence",
		// string-based enums for glTF
		ATTRIBUTES: "meshopt_decodeVertexBuffer",
		TRIANGLES: "meshopt_decodeIndexBuffer",
		INDICES: "meshopt_decodeIndexSequence",
	};

	return {
		ready: promise,
		supported: true,
		decodeVertexBuffer: function(target, count, size, source, filter) {
			decode(instance.exports.meshopt_decodeVertexBuffer, target, count, size, source, instance.exports[filters[filter]]);
		},
		decodeIndexBuffer: function(target, count, size, source) {
			decode(instance.exports.meshopt_decodeIndexBuffer, target, count, size, source);
		},
		decodeIndexSequence: function(target, count, size, source) {
			decode(instance.exports.meshopt_decodeIndexSequence, target, count, size, source);
		},
		decodeGltfBuffer: function(target, count, size, source, mode, filter) {
			decode(instance.exports[decoders[mode]], target, count, size, source, instance.exports[filters[filter]]);
		}
	};
})();

if (typeof window !== 'undefined') { window.MeshoptDecoder = MeshoptDecoder; }


/**
 * Mind Wars hologram GLB pipeline — same shaders / layer stack as tools/hologram-viewer-epic (hologram-runtime.mjs).
 * Default numeric values match tools/presets/preset-default.json (fetch can override in arena boot).
 * Requires global THREE (r128+).
 */
(function (global) {
  'use strict';
  var THREE = global.THREE;
  if (!THREE) return;

  /** Mirrors tools/presets/preset-default.json */
  var PRESET_DEFAULT = {
    colorR: 0,
    colorG: 0.61,
    colorB: 3,
    opacity: 0.6,
    fresnelStrength: 0.4,
    innerGlow: 0.45,
    rimStrength: 1.4,
    pulseSpeed: 1.75,
    pulseStrength: 0.32,
    scanSpeed: 2.5,
    scanDensity: 20,
    flickerIntensity: 0.04,
    baseOpacity: 1,
    texOpacity: 0.38,
    holoOpacityMul: 1,
    ringOpacity: 0.55,
    ringPulseSpeed: 2.2,
    beamIntensity: 0.18
  };

  var holoVertexShader = [
    'varying vec3 vNormal;',
    'varying vec3 vViewDir;',
    'varying vec3 vWorldPos;',
    'varying vec2 vUv;',
    'void main() {',
    '  vUv = uv;',
    '  vec4 worldPos = modelMatrix * vec4(position, 1.0);',
    '  vWorldPos = worldPos.xyz;',
    '  vNormal = normalize(normalMatrix * normal);',
    '  vec4 mvPos = modelViewMatrix * vec4(position, 1.0);',
    '  vViewDir = normalize(-mvPos.xyz);',
    '  gl_Position = projectionMatrix * mvPos;',
    '}'
  ].join('\n');

  var holoFragmentShader = [
    'uniform float uTime;',
    'uniform vec3  uColor;',
    'uniform float uOpacity;',
    'uniform float uFresnelStrength;',
    'uniform float uInnerGlow;',
    'uniform float uRimStrength;',
    'uniform float uPulseSpeed;',
    'uniform float uPulseStrength;',
    'uniform float uScanSpeed;',
    'uniform float uScanDensity;',
    'uniform float uFlickerIntensity;',
    'varying vec3 vNormal;',
    'varying vec3 vViewDir;',
    'varying vec3 vWorldPos;',
    'varying vec2 vUv;',
    'void main() {',
    '  float fresnel = 1.0 - max(dot(vNormal, vViewDir), 0.0);',
    '  fresnel = pow(fresnel, uFresnelStrength);',
    '  float scanLine = sin(vWorldPos.y * uScanDensity + uTime * uScanSpeed) * 0.5 + 0.5;',
    '  scanLine = pow(scanLine, 3.0) * 0.35 + 0.65;',
    '  float pulse  = sin(uTime * uPulseSpeed) * 0.5 + 0.5;',
    '  float pulse2 = sin(uTime * uPulseSpeed * 0.4 + vWorldPos.y * 3.0) * 0.5 + 0.5;',
    '  float energy = mix(pulse, pulse2, 0.4);',
    '  float inner = 1.0 - fresnel;',
    '  float core  = pow(inner, 3.5) * uInnerGlow;',
    '  float rim = pow(fresnel, 1.2) * uRimStrength;',
    '  float alpha = (rim + core) * scanLine * (1.0 - uPulseStrength + energy * uPulseStrength);',
    '  alpha = clamp(alpha, 0.0, 1.0);',
    '  float flicker = 1.0 - uFlickerIntensity + uFlickerIntensity * sin(uTime * 17.3 + vUv.y * 100.0);',
    '  alpha *= flicker;',
    '  vec3 col = uColor * (0.9 + rim * 0.4 + core * 0.5);',
    '  col = clamp(col, 0.0, 3.0);',
    '  gl_FragColor = vec4(col, alpha * uOpacity);',
    '}'
  ].join('\n');

  function mergeP(P) {
    var o = {};
    for (var k in PRESET_DEFAULT) {
      if (Object.prototype.hasOwnProperty.call(PRESET_DEFAULT, k)) o[k] = PRESET_DEFAULT[k];
    }
    if (P) {
      for (var k2 in P) {
        if (Object.prototype.hasOwnProperty.call(P, k2)) o[k2] = P[k2];
      }
    }
    return o;
  }

  function applyToUniforms(uniforms, P) {
    uniforms.uColor.value.set(P.colorR, P.colorG, P.colorB);
    uniforms.uOpacity.value = P.opacity * P.holoOpacityMul;
    uniforms.uFresnelStrength.value = P.fresnelStrength;
    uniforms.uInnerGlow.value = P.innerGlow;
    uniforms.uRimStrength.value = P.rimStrength;
    uniforms.uPulseSpeed.value = P.pulseSpeed;
    uniforms.uPulseStrength.value = P.pulseStrength;
    uniforms.uScanSpeed.value = P.scanSpeed;
    uniforms.uScanDensity.value = P.scanDensity;
    uniforms.uFlickerIntensity.value = P.flickerIntensity;
  }

  /**
   * @param {object} gltf — GLTFLoader result
   * @param {THREE.Group} targetGroup — parent for hologram meshes (cleared first)
   * @param {object} P — preset (merged with defaults)
   * @param {object} options — { shaderUniforms: [], targetHeight, enemyTint }
   */
  function buildIntoGroup(gltf, targetGroup, P, options) {
    var Pm = mergeP(P);
    if (options && options.enemyTint) {
      Pm.colorR = Math.min(2.2, Pm.colorR + 0.55);
      Pm.colorG = Math.max(0, Pm.colorG * 0.45);
      Pm.colorB = Math.min(3.5, Pm.colorB + 0.35);
    }
    var targetHeight = (options && options.targetHeight) || 1.15;
    var outUni = options && options.shaderUniforms;
    if (outUni) outUni.length = 0;

    while (targetGroup.children.length) {
      targetGroup.remove(targetGroup.children[0]);
    }

    var root = gltf.scene.clone(true);
    var box = new THREE.Box3().setFromObject(root);
    var center = new THREE.Vector3();
    box.getCenter(center);
    var size = new THREE.Vector3();
    box.getSize(size);
    var maxDim = Math.max(size.x, size.y, size.z, 0.001);
    var scale = targetHeight / maxDim;
    root.position.sub(center);
    root.scale.setScalar(scale);
    var box2 = new THREE.Box3().setFromObject(root);
    root.position.y -= box2.min.y;
    root.updateMatrixWorld(true);

    var modelGroup = new THREE.Group();
    root.traverse(function (child) {
      var drawable = child.isMesh === true || child.isSkinnedMesh === true;
      if (!drawable || !child.geometry) return;
      var origMat = Array.isArray(child.material) ? child.material[0] : child.material;
      var geo = child.geometry;

      /* Layer 1: solid dark base — WRITES depth to prevent z-fighting */
      var texMap = origMat && origMat.map ? origMat.map : null;
      var baseMat = new THREE.MeshBasicMaterial({
        map: texMap,
        color: texMap ? 0x224444 : 0x0a2020,
        transparent: true,
        opacity: Pm.baseOpacity * 0.5,
        depthWrite: true,
        depthTest: true
      });
      var baseMesh = new THREE.Mesh(geo.clone(), baseMat);
      baseMesh.renderOrder = 0;
      baseMesh.applyMatrix4(child.matrixWorld);
      modelGroup.add(baseMesh);

      /* Layer 2: hologram shader — reads depth, additive on top */
      var uniforms = {
        uTime: { value: 0 },
        uColor: { value: new THREE.Vector3(Pm.colorR, Pm.colorG, Pm.colorB) },
        uOpacity: { value: Pm.opacity * Pm.holoOpacityMul },
        uFresnelStrength: { value: Pm.fresnelStrength },
        uInnerGlow: { value: Pm.innerGlow },
        uRimStrength: { value: Pm.rimStrength },
        uPulseSpeed: { value: Pm.pulseSpeed },
        uPulseStrength: { value: Pm.pulseStrength },
        uScanSpeed: { value: Pm.scanSpeed },
        uScanDensity: { value: Pm.scanDensity },
        uFlickerIntensity: { value: Pm.flickerIntensity }
      };
      applyToUniforms(uniforms, Pm);
      if (outUni) outUni.push(uniforms);

      var holoMat = new THREE.ShaderMaterial({
        uniforms: uniforms,
        vertexShader: holoVertexShader,
        fragmentShader: holoFragmentShader,
        transparent: true,
        depthWrite: false,
        depthTest: true,
        blending: THREE.AdditiveBlending,
        side: THREE.FrontSide
      });
      var holoMesh = new THREE.Mesh(geo.clone(), holoMat);
      holoMesh.renderOrder = 1;
      holoMesh.applyMatrix4(child.matrixWorld);
      modelGroup.add(holoMesh);
    });

    targetGroup.add(modelGroup);
  }

  global.MWHologramLayers = {
    PRESET_DEFAULT: PRESET_DEFAULT,
    buildIntoGroup: buildIntoGroup,
    mergePreset: mergeP
  };
})(typeof window !== 'undefined' ? window : this);
